import{_ as o,o as t,c as r,a4 as i}from"./chunks/framework.Cqne-ChA.js";const h=JSON.parse('{"title":"Success Stories","description":"","frontmatter":{},"headers":[],"relativePath":"SuccessStories.md","filePath":"SuccessStories.md","lastUpdated":1726847723000}'),a={name:"SuccessStories.md"};function s(n,e,c,l,d,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="success-stories" tabindex="-1">Success Stories <a class="header-anchor" href="#success-stories" aria-label="Permalink to &quot;Success Stories&quot;">​</a></h1><p>Discover how zopen community have made a positive impact to various organizations and developers. Read the testimonials from our community members below:</p><hr style="height:3px;background-color:grey;"><h4><i>&quot;We use the tools on USS for doing development. I have used linux and other open source tools for a long time. I&#39;m new to z/OS and USS. I tried using the rocket tools since it was more well known. Somewhere along the way I learned of your ports and switched over. I prefer your version of ports and the warm welcome of the developers. Keep up with the good work&quot;</i></h4><ul><li>John F. Davis, Software Developer, Broadcom</li></ul><hr style="height:3px;background-color:grey;"><h4><i> &quot;We have been looking for the z/OS USS environment to provide a state of the art &quot;Unix&quot; experience. Participating in the z/OS Open-source Guild meetings has allowed us to install, test and recommend additional tools to be included in the porting efforts. It reminds me of the positive experience in a previous IBM Sponsor User Research initiative. IBM is doing a great job leading all the participants.<br><br> Through this effort, I have learned that the GNU collection of &quot;free&quot; software (typically packaged with Linux distributions) is the z/OS Open-Source strategy. z/OS and GNU software are a robust combination for hosting on-prem cloud native applications. <b>We see tremendous value moving the platform forward adopting the zopen community.</b><br><br> We are excited to find out more about IBM&#39;s strategy regarding packaging, delivery, and support for enterprise use.&quot; </i></h4><ul><li>Gary, Director zCloud Technologies of a Large Financial Services Company</li></ul>',8)])])}const m=o(a,[["render",s]]);export{h as __pageData,m as default};
